    f.write("    print(sdir_list)\n\n")
    f.write("    for p in range(len(props)):\n")
    f.write("        print('Making ' + propn[p] + ' pictures ----', path[i], traj_name[i], sdir_list)\n")
    f.write("        cnt = 0\n\n")
    f.write("        for s in range(len(sdir_list)):\n")
    f.write('            rc("open " + path[i] + "/" + sdir_list[s] + "/1_atoms_stats" + pfils[p])\n')
